```cpp
#pragma once

#include <ranges>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace batch_insert_products {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string name;
  float price;
  std::string category;
  int stock;
};

/**
 * Function: Perform efficient batch insertion of product data using a transaction.
 * 
 * @param products List of products to insert
 * @return true if all inserts succeed, false otherwise
 */
bool batch_insert_products(const std::vector<Product>& products) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  const size_t batch_size = 100;

  // 1. Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }
  auto conn = conn_result.value();

  // 2. Drop the Product table if it exists and create it
  auto drop_result = (conn | drop<Product> | if_exists)();
  if (!drop_result) {
    return false;
  }

  // 3. Start a transaction
  auto begin_result = (conn | begin_transaction)();
  if (!begin_result) {
    return false;
  }

  // 4. Insert products in batches
  auto insert_result = insert_or_write(products | batched)(conn);
  if (!insert_result) {
    // 5. Rollback transaction on failure
    (conn | rollback)();
    return false;
  }

  // 6. Commit the transaction
  auto commit_result = (conn | commit)();
  if (!commit_result) {
    return false;
  }

  return true;
}

}  // namespace batch_insert_products
```

## Key Implementation Points:

1. **Database Connection**: Uses `sqlgen::sqlite::connect()` to establish connection to "test_db.sqlite"

2. **Table Management**: 
   - Drops the Product table using `drop<Product> | if_exists` pattern
   - Creates the table implicitly through the insert operation (handled by sqlgen)

3. **Transaction Handling**:
   - Starts transaction with `begin_transaction`
   - Commits on success, rolls back on failure

4. **Batch Insertion**:
   - Uses `insert_or_write` with `batched` range to process products in batches of 100
   - Handles the batching automatically through sqlgen's range processing

5. **Error Handling**: Properly checks results at each step and ensures transaction integrity

The implementation follows the sqlgen library patterns demonstrated in the reference materials, using the pipe operator (`|`) for method chaining and proper error handling through result checking.

