#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace delete_inactive_users {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::optional<sqlgen::DateTime> last_login;
  std::string status = "active";
};

int delete_inactive_users() {
  using namespace sqlgen::literals;

  // Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return 1; // Return error code if connection fails
  }
  auto conn = conn_result.value();

  // Start transaction
  auto begin_result = conn->begin_transaction();
  if (!begin_result) {
    return 1; // Return error code if transaction start fails
  }

  // Build and execute delete statement
  auto delete_stmt = sqlgen::delete_from<User> 
                   | sqlgen::where("last_login"_c < "2025-01-01");

  auto delete_result = delete_stmt(conn);
  if (!delete_result) {
    // Rollback transaction on delete failure
    conn->rollback();
    return 1;
  }

  // Commit transaction
  auto commit_result = conn->commit();
  if (!commit_result) {
    return 1; // Return error code if commit fails
  }

  return 0; // Success
}

} // namespace delete_inactive_users
