  using namespace sqlgen::literals;

  // Create column references using string literals
  auto user_id_col = "user_id"_c;
  auto name_col = "name"_c;
  auto email_col = "email"_c;

  // Build the query using sqlgen's fluent interface
  auto query = sqlgen::read<std::vector<ValidatedProfile>>
    | sqlgen::select_from<UserProfile>(
        sqlgen::trim(name_col).as<"trimmed_name">(),
        sqlgen::trim(email_col).as<"trimmed_email">(),
        sqlgen::length(sqlgen::trim(name_col)).as<"name_length">(),
        sqlgen::length(sqlgen::trim(email_col)).as<"email_length">(),
