  if (!conn_result.is_ok()) {
    return {}; // Return empty vector on connection failure
  }

  auto result = query(conn_result.value());
  if (result.is_ok()) {
    return result.value();
  } else {
    return {}; // Return empty vector on query failure
  }
}

}  // namespace trim_and_length_validation
